export function AboutUs() {
  return (
    <section id="about-us" className="bg-white py-10 md:py-24 scroll-mt-24">
      <div className="container mx-auto px-4 md:px-8 text-center">
        {/* 3. Updated heading colors */}
        <h2 className="text-3xl font-bold mb-4 text-[#8A5BD5]">
          All-In-One Site{" "}
          <span className="text-[#F48C06]">Management Platform</span>
        </h2>
        <p className="max-w-3xl mx-auto  font-normal text-[24px] leading-[180%] tracking-[0em] text-[#696984] text-center mb-12">
          Skiline is one powerful online software suite that combines all the
          tools needed to run a successful school or office.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12 mt-20">
          {featureData.map((feature, index) => (
            <div
              key={index}
              className="relative bg-white p-8 rounded-2xl shadow-lg text-center flex flex-col items-center border pt-12 mt-10 md:mt-0"
            >
              <div
                className={`
          absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 
          w-20 h-20 rounded-full flex items-center justify-center mb-10
          ${feature.bgColor}`}
              >
                {feature.icon}
              </div>
              <h3 className="text-3xl font-semibold mb-7 mt-4 ">
                {feature.title}
              </h3>
              <p className="text-[#3A3A3A] text-[20px] leading-[150%] w-[300px] mx-auto text-center ">
                {feature.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
